  1	import * as React from 'react';
  2	import {
  3	  ODFMCO_OPERATOR,
  4	  ODFMCO_OPERATOR_NAMESPACE,
  5	  ODR_CLUSTER_OPERATOR,
  6	  ODR_HUB_OPERATOR,
  7	  VOL_SYNC,
  8	} from '@odf/mco/constants';
  9	import HealthItem from '@odf/shared/dashboards/status-card/HealthItem';
 10	import {
 11	  ClusterServiceVersionKind,
 12	  ClusterServiceVersionPhase,
 13	} from '@odf/shared/types';
 14	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 15	import { getOperatorHealthState } from '@odf/shared/utils';
 16	import {
 17	  HealthState,
 18	  WatchK8sResource,
 19	  useK8sWatchResource,
 20	  PrometheusResponse,
 21	} from '@openshift-console/dynamic-plugin-sdk';
 22	import {
 23	  Card,
 24	  CardBody,
 25	  CardHeader,
 26	  CardTitle,
 27	  Gallery,
 28	  GalleryItem,
 29	  TextVariants,
 30	  Text,
 31	} from '@patternfly/react-core';
 32	import { DRClusterAppsMap } from '../../../../types';
 33	import {
 34	  OperatorStatusesContext,
 35	  DRResourcesContext,
 36	} from '../dr-dashboard-context';
 37	import './status-card.scss';
 38	
 39	const operatorResource: WatchK8sResource = {
 40	  kind: 'operators.coreos.com~v1alpha1~ClusterServiceVersion',
 41	  namespace: ODFMCO_OPERATOR_NAMESPACE,
 42	  isList: true,
 43	};
 44	const drOperators: string[] = [ODFMCO_OPERATOR, ODR_HUB_OPERATOR];
 45	const clusterCSVOperators: string[] = [ODR_CLUSTER_OPERATOR];
 46	// Monitoring non CSV operator as POD
 47	const clusterPodOperators: string[] = [VOL_SYNC];
 48	
 49	const getDRCombinedStatus = (
 50	  csvHubData: ClusterServiceVersionKind[],
 51	  csvHubLoaded: boolean,
 52	  csvHubError: any
 53	) => {
 54	  const operatorsPhase = drOperators.map(
 55	    (drOperator) =>
 56	      csvHubData?.find((csv) => csv.metadata.name.startsWith(drOperator))
 57	        ?.status?.phase
 58	  );
 59	  const worstPhase =
 60	    operatorsPhase?.find(
 61	      (phase) => phase !== ClusterServiceVersionPhase.CSVPhaseSucceeded
 62	    ) || ClusterServiceVersionPhase.CSVPhaseSucceeded;
 63	  return getOperatorHealthState(worstPhase, !csvHubLoaded, csvHubError);
 64	};
 65	
 66	const getClusterWiseHealth = (
 67	  prometheusResponse: PrometheusResponse,
 68	  operators: string[],
 69	  label: string,
 70	  drClusters: string[],
 71	  clusterHealthStatus: ClusterWiseHealth
 72	): ClusterWiseHealth => {
 73	  return prometheusResponse?.data?.result?.reduce((acc, item) => {
 74	    const cluster = item?.metric.cluster;
 75	    let count = acc?.[cluster] || 0;
 76	    acc =
 77	      drClusters.includes(cluster) &&
 78	      !!operators.find((operator: string) =>
 79	        item?.metric?.[label].startsWith(operator)
 80	      )
 81	        ? { ...acc, [cluster]: item?.value[1] !== '1' ? count : count + 1 }
 82	        : acc;
 83	    return acc;
 84	  }, clusterHealthStatus);
 85	};
 86	
 87	const getClustersOperatorHealth = (
 88	  csvManagedData: PrometheusResponse,
 89	  drClusterAppsMap: DRClusterAppsMap,
 90	  podManagedData: PrometheusResponse
 91	) => {
 92	  const drClusters = Object.keys(drClusterAppsMap);
 93	  // Create cluster wise health map
 94	  let clusterWiseHealth: ClusterWiseHealth = getClusterWiseHealth(
 95	    csvManagedData,
 96	    clusterCSVOperators,
 97	    'name',
 98	    drClusters,
 99	    {}
100	  );
101	  // Update cluster wise health map
102	  clusterWiseHealth = getClusterWiseHealth(
103	    podManagedData,
104	    clusterPodOperators,
105	    'pod',
106	    drClusters,
107	    clusterWiseHealth
108	  );
109	  return drClusters?.every(
110	    (cluster) =>
111	      clusterWiseHealth?.[cluster] ===
112	      clusterCSVOperators.length + clusterPodOperators.length
113	  )
114	    ? HealthState.OK
115	    : HealthState.ERROR;
116	};
117	
118	export const StatusCard: React.FC = () => {
119	  const { t } = useCustomTranslation();
120	  const [csvHubData, csvHubLoaded, csvHubError] =
121	    useK8sWatchResource<ClusterServiceVersionKind[]>(operatorResource);
122	
123	  const {
124	    csvStatus: {
125	      data: csvManagedData,
126	      error: csvManagedError,
127	      loading: csvManagedLoading,
128	    },
129	    podStatus: {
130	      data: podManagedData,
131	      error: podManagedError,
132	      loading: podManagedLoading,
133	    },
134	  } = React.useContext(OperatorStatusesContext);
135	
136	  const { drClusterAppsMap, loaded, loadError } =
137	    React.useContext(DRResourcesContext);
138	
139	  // combined status of all DR hub operators (odr-hub and odf-mco)
140	  const drOperatorsHealthStatus = getDRCombinedStatus(
141	    csvHubData,
142	    csvHubLoaded,
143	    csvHubError
144	  ).state;
145	  const allManagedLoaded = loaded && !csvManagedLoading && !podManagedLoading;
146	  const anyManagedError = csvManagedError || loadError || podManagedError;
147	  // combined status of all cluster operators (odr-cluster and vol-sync)
148	  const clusterOperatorHealthStatus = React.useMemo(() => {
149	    if (!allManagedLoaded && !anyManagedError) return HealthState.LOADING;
150	    if (anyManagedError) return HealthState.NOT_AVAILABLE;
151	    return getClustersOperatorHealth(
152	      csvManagedData,
153	      drClusterAppsMap,
154	      podManagedData
155	    );
156	  }, [
157	    csvManagedData,
158	    drClusterAppsMap,
159	    allManagedLoaded,
160	    anyManagedError,
161	    podManagedData,
162	  ]);
163	
164	  return (
165	    <Card data-test="operator-status-card">
166	      <CardHeader className="mco-status__text--divider">
167	        <CardTitle>
168	          <Text component={TextVariants.h3}>{t('Operator status')}</Text>
169	        </CardTitle>
170	      </CardHeader>
171	      <CardBody>
172	        <Gallery hasGutter>
173	          <GalleryItem>
174	            <HealthItem
175	              title={t('Disaster recovery')}
176	              state={drOperatorsHealthStatus}
177	              className="mco-dashboard__statusText--size"
178	            />
179	          </GalleryItem>
180	          <GalleryItem>
181	            <HealthItem
182	              title={t('Cluster operator')}
183	              state={clusterOperatorHealthStatus}
184	              className="mco-dashboard__statusText--size"
185	            />
186	          </GalleryItem>
187	        </Gallery>
188	      </CardBody>
189	    </Card>
190	  );
191	};
192	
193	type ClusterWiseHealth = {
194	  [name in string]: number;
195	};

